// Validate required fields in alert webhook payload
const payload = $input.first().json;

const requiredFields = ['alert_type', 'severity', 'title', 'affected_resource'];
const missing = requiredFields.filter(field => !payload[field]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Validate severity enum
const validSeverities = ['critical', 'warning', 'info'];
if (!validSeverities.includes(payload.severity)) {
  throw new Error(`Invalid severity: ${payload.severity}. Must be one of: ${validSeverities.join(', ')}`);
}

// Pass through validated payload
return [{
  json: {
    alert_type: payload.alert_type,
    severity: payload.severity,
    title: payload.title,
    description: payload.description || '',
    affected_resource: payload.affected_resource,
    source_system: payload.source_system || null,
    source_alert_id: payload.source_alert_id || null,
    metadata: payload.metadata || {}
  }
}];

// Merge config with payload, using defaults if config not found
const payload = $('Validate Payload').first().json;
const configResult = $input.first().json;

// Default config if none found in database
const defaultConfig = {
  creates_tasks: true,
  default_department: null,
  task_title_template: null,
  info_creates_task: false,
  accumulation_threshold: 3,
  accumulation_window_hours: 24,
  cooldown_after_completion_hours: 24,
  dismissed_cooldown_days: 7
};

// Use database config if found, otherwise defaults
const config = configResult.id ? configResult : defaultConfig;

return [{
  json: {
    ...payload,
    config: config
  }
}];

// Merge occurrence result with previous data
const prevData = $('Merge Config with Payload').first().json;
const occurrenceResult = $input.first().json;

return [{
  json: {
    ...prevData,
    occurrence_id: occurrenceResult.occurrence_id,
    should_create_task_from_accumulation: occurrenceResult.should_create_task,
    occurrence_count: occurrenceResult.occurrence_count
  }
}];

// Check if info alert should create a task
// Exception 1: info_creates_task config flag is true
// Exception 2: accumulation threshold reached (3x in 24h)

const data = $input.first().json;
const config = data.config;

const shouldProceed = 
  config.info_creates_task === true || 
  data.should_create_task_from_accumulation === true;

return [{
  json: {
    ...data,
    task_priority: 'low',
    proceed_to_task: shouldProceed,
    skip_reason: shouldProceed ? null : 'Info alert - no exceptions triggered'
  }
}];

// Handle dedupe check result
const prevData = $('Merge All Paths').first().json;
const dupeResult = $input.first().json;

// Build dedupe_key for new task
const dedupeKey = `${prevData.alert_type}:${prevData.affected_resource}`;

// Check if we found a duplicate
const hasDuplicate = dupeResult && dupeResult.id;
const duplicateStatus = hasDuplicate ? dupeResult.duplicate_status : 'none';

let action = 'create';
let existingTaskId = null;
let shouldEscalate = false;

if (hasDuplicate) {
  existingTaskId = dupeResult.id;

  if (duplicateStatus === 'duplicate_open') {
    // Check if we should escalate priority
    const priorityOrder = { 'low': 0, 'normal': 1, 'high': 2, 'critical': 3 };
    const existingPriority = priorityOrder[dupeResult.priority] || 0;
    const newPriority = priorityOrder[prevData.task_priority] || 0;

    if (newPriority > existingPriority) {
      action = 'escalate';
      shouldEscalate = true;
    } else {
      action = 'skip_duplicate';
    }
  } else if (duplicateStatus === 'dismissed_recently') {
    action = 'skip_dismissed';
  } else if (duplicateStatus === 'completed_recently') {
    action = 'skip_cooldown';
  }
}

return [{
  json: {
    ...prevData,
    dedupe_key: dedupeKey,
    action: action,
    existing_task_id: existingTaskId,
    should_escalate: shouldEscalate,
    existing_priority: hasDuplicate ? dupeResult.priority : null
  }
}];

