// Parse Claude API response and extract task_title and task_description
const prevData = $('Handle Duplicate Check').first().json;
const claudeResponse = $input.first().json;

try {
  // Check if Claude request failed
  if (!claudeResponse || !claudeResponse.content || !claudeResponse.content[0]) {
    throw new Error('Invalid Claude response structure');
  }

  // Extract text from Claude response
  const responseText = claudeResponse.content[0].text;

  // Parse JSON from response (handle markdown code blocks if present)
  let jsonText = responseText;
  if (responseText.includes('```json')) {
    jsonText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  } else if (responseText.includes('```')) {
    jsonText = responseText.replace(/```\n?/g, '').trim();
  }

  const parsed = JSON.parse(jsonText);

  if (!parsed.task_title || !parsed.task_description) {
    throw new Error('Missing task_title or task_description in Claude response');
  }

  return [{
    json: {
      ...prevData,
      task_title: parsed.task_title,
      task_description: parsed.task_description,
      ai_transform_success: true
    }
  }];
} catch (error) {
  // Return with flag for fallback processing
  return [{
    json: {
      ...prevData,
      ai_transform_success: false,
      ai_error: error.message
    }
  }];
}

// Fallback transformation when Claude API fails
const data = $input.first().json;

// Simple transformation patterns based on alert type
const actionVerbs = {
  'ssl_expiry': 'Renew',
  'domain_health': 'Investigate',
  'uptime_down': 'Restore',
  'payment_failed': 'Resolve',
  'tier_ending': 'Address',
  'vip_non_response': 'Follow up on',
  'link_broken': 'Fix',
  'lighthouse_issue': 'Optimize'
};

const verb = actionVerbs[data.alert_type] || 'Address';

// Generate fallback title
let taskTitle = data.title;
if (!taskTitle.toLowerCase().startsWith(verb.toLowerCase())) {
  taskTitle = `${verb}: ${data.title}`;
}

// Generate fallback description
let taskDescription = data.description || '';
if (data.affected_resource) {
  taskDescription += taskDescription ? `\n\nAffected: ${data.affected_resource}` : `Affected: ${data.affected_resource}`;
}

return [{
  json: {
    ...data,
    task_title: taskTitle,
    task_description: taskDescription,
    ai_transform_success: false,
    used_fallback: true
  }
}];

// Map department from config or defaults
const data = $input.first().json;
const configDepartment = data.config?.default_department;

// Use config department if available, otherwise map defaults
const departmentMap = {
  'ssl_expiry': 'Digital',
  'domain_health': 'Digital',
  'uptime_down': 'Digital',
  'payment_failed': 'Operations',
  'tier_ending': 'Programs',
  'vip_non_response': 'Programs',
  'link_broken': 'Digital',
  'lighthouse_issue': 'Digital'
};

const department = configDepartment || departmentMap[data.alert_type] || 'Operations';

// Calculate due date based on priority
let dueDate = new Date();
let dueTime = null;

switch (data.task_priority) {
  case 'critical':
    // Due today, within 4 hours
    dueDate.setHours(dueDate.getHours() + 4);
    dueTime = dueDate.toTimeString().slice(0, 5);
    break;
  case 'high':
    // Due end of next business day
    dueDate.setDate(dueDate.getDate() + 1);
    dueTime = '17:00';
    break;
  case 'normal':
    // Due in 3 days
    dueDate.setDate(dueDate.getDate() + 3);
    break;
  case 'low':
    // Due in 7 days
    dueDate.setDate(dueDate.getDate() + 7);
    break;
}

return [{
  json: {
    ...data,
    department: department,
    calculated_due_date: dueDate.toISOString().split('T')[0],
    calculated_due_time: dueTime
  }
}];

// Error handler - extract error details
const error = $execution.customData?.error || $input.first()?.error || 'Unknown error';
const errorMessage = typeof error === 'string' ? error : error.message || JSON.stringify(error);

return [{
  json: {
    success: false,
    action: 'error',
    error: errorMessage,
    timestamp: new Date().toISOString()
  }
}];

